import{_ as a,c as o,o as r,b as e,d as s}from"./app.ea4ad862.js";const E=JSON.parse('{"title":"Equipo de Pruebas","description":"","frontmatter":{},"headers":[],"relativePath":"roles/test-team.md"}'),t={name:"roles/test-team.md"},n=e("h1",{id:"equipo-de-pruebas",tabindex:"-1"},[s("Equipo de Pruebas "),e("a",{class:"header-anchor",href:"#equipo-de-pruebas","aria-hidden":"true"},"#")],-1),d=e("p",null,"La calidad de un producto no puede ser garantizada si no se han realizados cada una de las respectivas pruebas. Por lo tanto, se recomienda contar con un equipo bien dispuesto y altamente comprometido para este prop\xF3sito.",-1),u=e("p",null,"El trabajo que debe realizar este equipo se considera una labor bastante noble y honrosa, porque hacerle pruebas continuas a un mismo producto de software, es decir, una y otra vez hasta m\xE1s all\xE1 de lo necesario, es un trabajo forzado que requiere de mucho empe\xF1o.",-1),l=e("p",null,"Cuando se habla de una y otra vez, se refiere a que cada vez que ocurra un cambio en el c\xF3digo fuente (cosa que siempre pasa), bien sea por un requerimiento del usuario, por una mejora funcional implementada por los desarrolladores, o hasta que se corrija un error detectado, es important\xEDsimo que se repitan todas las pruebas necesarias por m\xE1s tediosas que estas puedan resultar.",-1),i=e("p",null,"Por m\xE1s esfuerzo que el Equipo de Desarrollo haga realizando pruebas directamente en el c\xF3digo, siempre habr\xE1n errores que el ojo del programador no podr\xE1 detectar. Es que, para detectar este tipo de errores o fallas, se necesita muchas veces hasta la inocencia de un usuario no experto en tecnolog\xEDa de software. Por lo tanto, un Equipo de Pruebas debe estar conformado por un grupo variado de personas con un \xFAnico objetivo: encontrar fallas en el software.",-1),c=e("p",null,"El Equipo de Pruebas nunca debe estar fundamentado bajo la idea de querer supervisar y evaluar el trabajo de los desarrolladores. M\xE1s bien, su idea fundamental es ayudar al Equipo de Desarrollo para que el incremento del Sprint (el producto) sea de la m\xE1s alt\xEDsima calidad en el menor tiempo posible.",-1),p=e("p",null,"Generalmente, el Equipo de Pruebas est\xE1 conformado por un grupo de personas contratadas para tal fin. Muchas veces, las pruebas las hace tambi\xE9n el Gestor del Proyecto, sobre todo para asegurarse personalmente de la calidad ofrecida al Due\xF1o del Producto. Otras veces, se cuenta con un grupo de usuarios finales muy interesados en el producto, que ofrecen sus servicios para tal prop\xF3sito. Algunas otras, un(os) desarrollador(es) tambi\xE9n realiza(n) estas pruebas manuales, pero esto no es recomendado. Por \xFAltimo, mientras m\xE1s personas prueben el producto, se detecten las fallas a tiempo y estas sean notificadas para ser corregidas a tiempo, se garantizar\xE1 una alta colaboraci\xF3n con el desarrollo del proyecto.",-1),m=e("p",null,"Igualmente, el Equipo de Pruebas colabora, sobre todo cuando no hay muchas funcionalidades nuevas que probar, elaborando documentaci\xF3n, manual(es) e inducci\xF3n(es), o cualquier otra(s) actividad(es) referente al proyecto.",-1),b=[n,d,u,l,i,c,p,m];function h(q,f,_,v,g,P){return r(),o("div",null,b)}const z=a(t,[["render",h]]);export{E as __pageData,z as default};
